export function getFormula(id: string): FormulaFunction {
  const fn = formulaRegistry[id];
  if (!fn) {
    throw new Error(
      `Formula not found: "${id}". Run "npm run generate:registry" to rebuild the formula index.`
    );
  }
  return fn;
}

export default formulaRegistry;
